import{_ as a,o as r,c as o,ae as l}from"./chunks/framework.Czhw_PXq.js";const g=JSON.parse('{"title":"《让时间陪你慢慢变富》第2讲：证券交易市场是世界第九大奇迹","description":"为什么证券交易市场被称为世界第九大奇迹？普通人如何当老板？","frontmatter":{"title":"《让时间陪你慢慢变富》第2讲：证券交易市场是世界第九大奇迹","description":"为什么证券交易市场被称为世界第九大奇迹？普通人如何当老板？","pubDate":"2026-05-16"},"headers":[],"relativePath":"posts/lixiaolai-dt-02.md","filePath":"posts/lixiaolai-dt-02.md"}'),e={name:"posts/lixiaolai-dt-02.md"};function i(n,t,s,h,d,p){return r(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="第2讲-证券交易市场是世界第九大奇迹" tabindex="-1">第2讲：证券交易市场是世界第九大奇迹 <a class="header-anchor" href="#第2讲-证券交易市场是世界第九大奇迹" aria-label="Permalink to &quot;第2讲：证券交易市场是世界第九大奇迹&quot;">​</a></h1><blockquote><p>证券交易市场为普通人提供了一个&quot;若是没有它就不可能有&quot;的绝佳机会，什么机会啊？通俗点讲，就是任何人都可以当老板的机会。</p></blockquote><h2 id="引言-世界第八大奇迹之后" tabindex="-1">引言：世界第八大奇迹之后 <a class="header-anchor" href="#引言-世界第八大奇迹之后" aria-label="Permalink to &quot;引言：世界第八大奇迹之后&quot;">​</a></h2><p>爱因斯坦曾经将&quot;复利&quot;称为世界第八大奇迹。</p><p>而李笑来认为，传统的<strong>证券交易市场</strong>绝对值得被称为<strong>世界第九大奇迹</strong>。</p><p>为什么？因为在这个神奇的市场里，普通人获得了前所未有的机会。</p><h2 id="第一部分-普通人的创业困境" tabindex="-1">第一部分：普通人的创业困境 <a class="header-anchor" href="#第一部分-普通人的创业困境" aria-label="Permalink to &quot;第一部分：普通人的创业困境&quot;">​</a></h2><h3 id="创业故事的误导" tabindex="-1">创业故事的误导 <a class="header-anchor" href="#创业故事的误导" aria-label="Permalink to &quot;创业故事的误导&quot;">​</a></h3><p>我们天天被各种创业故事所吸引：</p><ul><li>出身草根的主角</li><li>最终完成逆袭</li><li>成为独角兽缔造者</li><li>上市公司董事长</li></ul><p><strong>激动人心！但问题在于：</strong></p><blockquote><p><strong>既然事实已经证明他们能够创造出那么大的商业价值，他们就不是普通人</strong>——他们是极端出色的人，无论他们是否出身草根，无论他们早期是否贫困，成功本身只是在证明他们本来就是具备成功特质的人。</p></blockquote><h3 id="创业成功的真相" tabindex="-1">创业成功的真相 <a class="header-anchor" href="#创业成功的真相" aria-label="Permalink to &quot;创业成功的真相&quot;">​</a></h3><p>即便是如此优秀、如此努力的人，最终的成功，更多靠的还是<strong>运气</strong>——他们要有足够的好运去获得趋势的支撑。</p><h3 id="在上市公司工作的局限" tabindex="-1">在上市公司工作的局限 <a class="header-anchor" href="#在上市公司工作的局限" aria-label="Permalink to &quot;在上市公司工作的局限&quot;">​</a></h3><p>即便是在上市公司工作，也无法跟运气摆脱干系：</p><ul><li>恰好早期加入一家将来能够上市的公司——这是运气</li><li>等到公司上市时，依然在理念上、能力上、关系上都跟得上——概率极低</li><li>在公司上市前应聘成功——需要年龄、学历、能力都恰好匹配</li></ul><p><strong>更大的问题：</strong> 有多少人实际持有公司的股票？</p><p>没有公司的股票，就意味着自己无论如何努力，公司的发展跟自己都没有任何实际关系。</p><h2 id="第二部分-证券交易所的奇迹" tabindex="-1">第二部分：证券交易所的奇迹 <a class="header-anchor" href="#第二部分-证券交易所的奇迹" aria-label="Permalink to &quot;第二部分：证券交易所的奇迹&quot;">​</a></h2><h3 id="奇迹的本质" tabindex="-1">奇迹的本质 <a class="header-anchor" href="#奇迹的本质" aria-label="Permalink to &quot;奇迹的本质&quot;">​</a></h3><p>因为有证券交易所的存在，无论是谁——</p><blockquote><p><strong>不分种族、不分国籍、不分地域、不分性别、不分年龄、不分高矮胖瘦美丑，也不分何种性取向</strong>——都可以在任何时间点上购买世界上最优秀的企业的股票，让自己的钱24小时不间断地跟随着那些世界上最优秀的企业共同成长。</p></blockquote><p>这才是真正有质量的&quot;拼&quot;！</p><h3 id="零门槛的机会" tabindex="-1">零门槛的机会 <a class="header-anchor" href="#零门槛的机会" aria-label="Permalink to &quot;零门槛的机会&quot;">​</a></h3><p>尤为惊人的是，在正常的情况下，作为投资者，这些普通人完全不需要额外做任何事情——购买世界上最优秀的企业的股票，竟然<strong>几乎没有任何门槛</strong>！</p><h3 id="从普通人到老板" tabindex="-1">从普通人到老板 <a class="header-anchor" href="#从普通人到老板" aria-label="Permalink to &quot;从普通人到老板&quot;">​</a></h3><p>普通人的钱，是不大可能有什么有效的增值机会的，因为普通人很难创造真正的商业价值。</p><p>人群中只有极少数人在想尽一切办法创造商业价值，以改变自己的命运，并且最后成功做到。</p><p>证券交易市场上的企业，虽然也有垃圾企业，但毕竟是按照一定的标准严格筛选出来的企业，人群中真正善于创造商业价值的人才绝大部分都集中在那里。</p><p><strong>关键转变：</strong></p><p>只要普通人用自己的钱购买了优秀的企业的股票，那即意味着，普通人因此<strong>瞬间升级为老板</strong>，而那些最会创造商业价值的人就在为这些普通人打工——哪怕这些普通人事实上肯定是&quot;无能的老板&quot;。</p><h2 id="第三部分-选择股票其实很简单" tabindex="-1">第三部分：选择股票其实很简单 <a class="header-anchor" href="#第三部分-选择股票其实很简单" aria-label="Permalink to &quot;第三部分：选择股票其实很简单&quot;">​</a></h2><h3 id="困难是幻觉" tabindex="-1">困难是幻觉 <a class="header-anchor" href="#困难是幻觉" aria-label="Permalink to &quot;困难是幻觉&quot;">​</a></h3><p>人们总以为&quot;选择股票&quot;是很困难的事情——其实，<strong>一点都不难</strong>！</p><p>那所谓的&quot;困难&quot;，完全是惯性思维造成的，实际上，那只不过是人们总是不肯或者不敢使用最简单直接粗暴有效的方法的结果。</p><h3 id="最简单有效的方法" tabindex="-1">最简单有效的方法 <a class="header-anchor" href="#最简单有效的方法" aria-label="Permalink to &quot;最简单有效的方法&quot;">​</a></h3><p>这个方法太简单了，简单到令人难以置信：</p><blockquote><p><strong>直接选择市场上所有人都最看好的股票。</strong></p></blockquote><p>注意这个&quot;最&quot;字。</p><table tabindex="0"><thead><tr><th>交易所</th><th>直接买</th></tr></thead><tbody><tr><td>深交所</td><td>万科</td></tr><tr><td>上交所</td><td>贵州茅台</td></tr><tr><td>纳斯达克</td><td>苹果</td></tr><tr><td>港交所</td><td>腾讯</td></tr></tbody></table><h3 id="利用他人的智慧" tabindex="-1">利用他人的智慧 <a class="header-anchor" href="#利用他人的智慧" aria-label="Permalink to &quot;利用他人的智慧&quot;">​</a></h3><p>这就是交易市场的神奇之处——在这里，<strong>你可以利用他人的智慧</strong>。</p><p><strong>你不是不会吗？你不是不懂吗？你不是觉得自己笨吗？</strong></p><p>其实，你想多了，因为这些都不重要——你不是佩服巴菲特吗？那你就直接去买他正在持有的公司，这就相当于是让巴菲特免费为你思考……</p><p>当然，巴菲特也不见得是最好的，那怎么办？</p><p>你可以直接选择所有人都看好的那个标的。万科、茅台、苹果、腾讯，都是市场上最聪明的人们已经帮你选好了的品种——并且这些最聪明的人提供的建议竟然是<strong>彻头彻尾免费的</strong>！</p><h3 id="为什么99-的人不采用" tabindex="-1">为什么99%的人不采用 <a class="header-anchor" href="#为什么99-的人不采用" aria-label="Permalink to &quot;为什么99%的人不采用&quot;">​</a></h3><p>你知道最神奇的是什么吗？这种最简单直接粗暴且肯定有效的方法，<strong>99%以上的人并不采用</strong>！</p><p><strong>数据说话：</strong></p><p>据2019年3月31日统计：</p><ul><li>贵州茅台（600519）股东总数：80,594户</li><li>同期中国股市开户户数累计：约1.5亿</li><li>比例：约万分之五</li></ul><p>这里面还有大量的机构投资者，也就是说，普通人中，也许只有<strong>万分之一</strong>不到的人敢用这种简单直接粗暴却极其有效的原则。</p><h2 id="第四部分-最高境界的投资" tabindex="-1">第四部分：最高境界的投资 <a class="header-anchor" href="#第四部分-最高境界的投资" aria-label="Permalink to &quot;第四部分：最高境界的投资&quot;">​</a></h2><h3 id="什么都不用做" tabindex="-1">什么都不用做 <a class="header-anchor" href="#什么都不用做" aria-label="Permalink to &quot;什么都不用做&quot;">​</a></h3><p>如果你选择了市场上最被看好的那个标的，由此产生的效果是什么？</p><p>接下来，你不需要研究，你不需要分析，你不需要独自盯盘，甚至你根本就不需要与任何人讨论，事实上，<strong>什么都不用你做</strong>，因为所有这些，都由市场上最聪明的人替你做完了，并且<strong>免费</strong>！</p><p>这绝对是现代交易市场上投资者的<strong>最高境界</strong>。</p><h3 id="茅台股东的生活" tabindex="-1">茅台股东的生活 <a class="header-anchor" href="#茅台股东的生活" aria-label="Permalink to &quot;茅台股东的生活&quot;">​</a></h3><p>传闻说，茅台股东的生活也很简单：</p><ul><li>读书</li><li>健身</li><li>旅游</li><li>陪家人</li></ul><p>这的确是真实的。</p><p>因此，难道证券交易市场不应该被称为世界第九大奇迹吗？</p><h2 id="第五部分-实战应用" tabindex="-1">第五部分：实战应用 <a class="header-anchor" href="#第五部分-实战应用" aria-label="Permalink to &quot;第五部分：实战应用&quot;">​</a></h2><h3 id="标的选择原则" tabindex="-1">标的选择原则 <a class="header-anchor" href="#标的选择原则" aria-label="Permalink to &quot;标的选择原则&quot;">​</a></h3><ol><li><p><strong>选择市场上最被看好的</strong></p><ul><li>市值大</li><li>流动性好</li><li>业绩稳定</li></ul></li><li><p><strong>利用他人的智慧</strong></p><ul><li>关注机构重仓股</li><li>参考指数基金成分股</li><li>选择行业龙头</li></ul></li><li><p><strong>保持简单</strong></p><ul><li>不追求复杂策略</li><li>不试图战胜市场</li><li>相信集体的智慧</li></ul></li></ol><h3 id="常见错误" tabindex="-1">常见错误 <a class="header-anchor" href="#常见错误" aria-label="Permalink to &quot;常见错误&quot;">​</a></h3><table tabindex="0"><thead><tr><th>错误</th><th>表现</th><th>后果</th></tr></thead><tbody><tr><td>过度研究</td><td>试图分析所有股票</td><td>信息过载，无法决策</td></tr><tr><td>频繁交易</td><td>不断买卖</td><td>成本高，收益低</td></tr><tr><td>追热点</td><td>买概念题材股</td><td>风险大，易被套</td></tr><tr><td>不听建议</td><td>固执己见</td><td>错过最佳标的</td></tr></tbody></table><h2 id="第六部分-常见陷阱与误区" tabindex="-1">第六部分：常见陷阱与误区 <a class="header-anchor" href="#第六部分-常见陷阱与误区" aria-label="Permalink to &quot;第六部分：常见陷阱与误区&quot;">​</a></h2><h3 id="陷阱一-选择困难症" tabindex="-1">陷阱一：选择困难症 <a class="header-anchor" href="#陷阱一-选择困难症" aria-label="Permalink to &quot;陷阱一：选择困难症&quot;">​</a></h3><p><strong>表现</strong>：面对太多股票，不知道选哪个</p><p><strong>解决</strong>：直接选市场最看好的那个，简单直接</p><h3 id="陷阱二-过度自信" tabindex="-1">陷阱二：过度自信 <a class="header-anchor" href="#陷阱二-过度自信" aria-label="Permalink to &quot;陷阱二：过度自信&quot;">​</a></h3><p><strong>表现</strong>：认为自己能选出比市场更好的股票</p><p><strong>解决</strong>：承认市场集体的智慧超过个人</p><h3 id="陷阱三-忽视流动性" tabindex="-1">陷阱三：忽视流动性 <a class="header-anchor" href="#陷阱三-忽视流动性" aria-label="Permalink to &quot;陷阱三：忽视流动性&quot;">​</a></h3><p><strong>表现</strong>：买小盘股、冷门股</p><p><strong>解决</strong>：选择大盘股，流动性好的标的</p><h3 id="陷阱四-追求刺激" tabindex="-1">陷阱四：追求刺激 <a class="header-anchor" href="#陷阱四-追求刺激" aria-label="Permalink to &quot;陷阱四：追求刺激&quot;">​</a></h3><p><strong>表现</strong>：喜欢追涨杀跌，频繁交易</p><p><strong>解决</strong>：采用定投策略，长期持有</p><h2 id="本章总结" tabindex="-1">本章总结 <a class="header-anchor" href="#本章总结" aria-label="Permalink to &quot;本章总结&quot;">​</a></h2><h3 id="核心要点回顾" tabindex="-1">核心要点回顾 <a class="header-anchor" href="#核心要点回顾" aria-label="Permalink to &quot;核心要点回顾&quot;">​</a></h3><ol><li><strong>证券交易市场是世界第九大奇迹</strong>：普通人可以当老板的地方</li><li><strong>选择股票其实很简单</strong>：直接选市场最看好的</li><li><strong>可以利用他人的智慧</strong>：让最聪明的人免费帮你思考</li><li><strong>99%的人不采用简单方法</strong>：这是你的机会</li><li><strong>最高境界是什么都不做</strong>：让钱24小时为你工作</li></ol><h3 id="关键概念" tabindex="-1">关键概念 <a class="header-anchor" href="#关键概念" aria-label="Permalink to &quot;关键概念&quot;">​</a></h3><ul><li><strong>世界第九大奇迹</strong>：证券交易市场</li><li><strong>他人的智慧</strong>：利用市场集体智慧选择标的</li><li><strong>无能的老板</strong>：持有优秀公司股票但不参与经营的投资者</li><li><strong>最高境界</strong>：什么都不用做，让钱为你工作</li></ul><h3 id="行动建议" tabindex="-1">行动建议 <a class="header-anchor" href="#行动建议" aria-label="Permalink to &quot;行动建议&quot;">​</a></h3><ol><li><strong>确定交易所</strong>：你主要投资哪个市场？</li><li><strong>找出最被看好的标的</strong>：市值最大、流动性最好的</li><li><strong>开始定投</strong>：定期定额买入</li><li><strong>长期持有</strong>：让时间陪你慢慢变富</li></ol><h3 id="下章预告" tabindex="-1">下章预告 <a class="header-anchor" href="#下章预告" aria-label="Permalink to &quot;下章预告&quot;">​</a></h3><p>下一讲《普通人做投资的唯一正确方式》，我们将深入理解为什么定投是普通人唯一靠谱的投资方式，以及&quot;微笑曲线&quot;和&quot;猥琐曲线&quot;的奥秘。</p><hr><p><em>本文基于李笑来《让时间陪你慢慢变富》相关章节整理。</em></p>',92)])])}const q=a(e,[["render",i]]);export{g as __pageData,q as default};
